```python
import math
from collections import Counter
import re

def calculate_entropy(password):
    if not password:
        return 0

    # Calculate the frequency of each character
    freq = Counter(password)
    total_chars = len(password)
    entropy = 0

    for count in freq.values():
        prob = count / total_chars
        entropy -= prob * (prob * math.log2(prob))

    return entropy

def check_sequential_and_repeating_patterns(password):
    # Check for repeating characters
    if re.search(r'(.)\1{2,}', password):
        return "Password contains repeating characters. Avoid consecutive identical characters."
    # Check for sequential characters
    if re.search(r'([a-zA-Z])\1', password):
        return "Password contains sequential characters. Avoid patterns like 'abc'."

    return None

def check_common_words(password, common_words):
    if any(word in password.lower() for word in common_words):
        return "Password contains a common word. Choose a unique combination."
    return None

def generate_tips():
    tips = [
        "Use a mix of uppercase and lowercase letters.",
        "Include numbers and special characters.",
        "Avoid common words and patterns.",
        "Use a passphrase if possible.",
        "Change your password regularly."
    ]
    return tips

def evaluate_password_strength(password):
    # Initialize score
    score = 0

    # Minimum length requirement
    if len(password) < 12:
        return "Password is too short. It should be at least 12 characters long."

    # Character type checks
    has_uppercase = any(char.isupper() for char in password)
    has_lowercase = any(char.islower() for char in password)
    has_digit = any(char.isdigit() for char in password)
    has_special_char = any(not char.isalnum() for char in password)

    # Common word detection
    common_words = load_common_words('common_words.txt')
    if check_common_words(password, common_words):
        return "Password contains a common word. Choose a unique combination."

    # Sequential and repeating patterns
    if check_sequential_and_repeating_patterns(password):
        return "Password contains sequential or repeating characters. Avoid patterns like 'abc' or 'aaa'."

    # Entropy calculation
    entropy = calculate_entropy(password)
    if entropy < 3.5:  # Threshold for acceptable entropy
        return "Password is too predictable. Increase randomness."

    # Assign points based on criteria met
    if has_uppercase:
        score += 1
    if has_lowercase:
        score += 1
    if has_digit:
        score += 1
    if has_special_char:
        score += 1

    # Final score and feedback
    if score == 4:
        return "Strong Password"
    elif score >= 3:
        return "Good Password"
    elif score >= 2:
        return "Moderate Password"
    else:
        return "Weak Password"

def load_common_words(file_path):
    with open(file_path, 'r') as file:
        return [word.strip() for word in file.readlines()]

# Example usage
password = "SecureP@ssw0rd!"
strength = evaluate_password_strength(password)
print(strength)
```

